#include <stdio.h>
#include <stdbool.h> // For bool type

int main() {
    int num;
    scanf("%d", &num);

    bool is_prime = true;

    if (num <= 1) { // Numbers less than or equal to 1 are not prime
        is_prime = false;
    } else if (num == 2) { // 2 is the only even prime number
        is_prime = true;
    } else if (num % 2 == 0) { // All other even numbers are not prime
        is_prime = false;
    } else {
        // Check for divisibility by odd numbers starting from 3 up to num/2
        // We can go up to sqrt(num), but num/2 is simpler for introductory purposes.
        for (int i = 3; i * i <= num; i += 2) { // Optimized: check only odd divisors
            if (num % i == 0) {
                is_prime = false;
                break; // No need to check further if a divisor is found
            }
        }
    }

    if (is_prime) {
        printf("Prime\n");
    } else {
        printf("Not Prime\n");
    }

    return 0;
}
